class Solution {
    public List<Integer> beautifulIndices(String s, String a, String b, int k) {
        List<Integer> res = new ArrayList<>();
        int n = s.length(), m = a.length(), p = b.length();
        if (n < m || n < p) return res;

        List<Integer> aIdx = new ArrayList<>();
        List<Integer> bIdx = new ArrayList<>();

        // Collect indices for a
        for (int i = 0; i <= n - m; i++) {
            if (s.regionMatches(i, a, 0, m)) {
                aIdx.add(i);
            }
        }

        // Collect indices for b
        for (int j = 0; j <= n - p; j++) {
            if (s.regionMatches(j, b, 0, p)) {
                bIdx.add(j);
            }
        }

        if (aIdx.isEmpty() || bIdx.isEmpty()) return res;

        // Two-pointer check
        int i = 0, j = 0;
        int lenB = bIdx.size();
        for (int ai : aIdx) {
            while (j < lenB && bIdx.get(j) < ai - k) j++;
            if (j < lenB && Math.abs(bIdx.get(j) - ai) <= k) {
                res.add(ai);
                continue;
            }
            if (j > 0 && Math.abs(bIdx.get(j - 1) - ai) <= k) {
                res.add(ai);
            }
        }

        return res;
    }
}
